-- ============================================================================
-- >>> followups.sql
-- ============================================================================
-- ============================================================================
-- DemoTrack — Phase 6: Follow-up Workflows + Digest (Spec §6)
-- Standalone & idempotent. Run AFTER schema.sql with the service role.
--
-- Provides:
--   • follow_up_queue        — view: open sends with a computed due/overdue state
--   • log_overdue_no_responses() — auto-log 'no_response' feedback past 14 days
--   • queue_followup_notifications() — enqueue 7-day nudge / 14-day overdue rows
--   • run_followups_tick()   — the function pg_cron calls daily
--   • (guarded) pg_cron schedule + a commented pg_net → daily-digest snippet
--
-- Timing comes from submissions.follow_up_due_at (sent + 7d) and
-- submissions.overdue_at (sent + 14d), set when a demo is recorded.
-- ============================================================================

-- ---------------------------------------------------------------------------
-- The follow-up queue: every still-open send, with a state the UI can sort on.
-- security_invoker => the caller's RLS applies (each user sees only their own).
-- "open" = awaiting a reply (sent / opened). Replied/considering/signed/passed
-- have left the silence loop.
-- ---------------------------------------------------------------------------
create or replace view follow_up_queue
  with (security_invoker = true) as
select
  s.id              as submission_id,
  s.user_id,
  s.track_id,
  t.title           as track_title,
  s.contact_id,
  c.name            as contact_name,
  c.submission_method as method,
  c.email           as contact_email,
  c.portal_url,
  c.dm_link,
  s.status,
  s.sent_at,
  s.follow_up_due_at,
  s.overdue_at,
  s.no_response_logged,
  case
    when s.overdue_at      is not null and s.overdue_at      <= now() then 'overdue'
    when s.follow_up_due_at is not null and s.follow_up_due_at <= now() then 'due'
    else 'waiting'
  end as state
from submissions s
join tracks   t on t.id = s.track_id
join contacts c on c.id = s.contact_id
where s.user_id = auth.uid()
  and s.status in ('sent','opened');

-- ---------------------------------------------------------------------------
-- Silence is data: past the 14-day overdue window, auto-log a 'no_response'
-- feedback record exactly once (guarded by submissions.no_response_logged).
-- SECURITY DEFINER so the scheduler (no auth.uid()) can write across users;
-- user_id is copied from the submission, so rows stay correctly owned.
-- ---------------------------------------------------------------------------
create or replace function log_overdue_no_responses()
returns integer
language plpgsql
security definer
set search_path = public
as $$
declare
  logged int := 0;
begin
  with overdue as (
    select s.id, s.user_id, s.track_id, s.contact_id
    from submissions s
    where s.overdue_at is not null
      and s.overdue_at <= now()
      and s.no_response_logged = false
      and s.status in ('sent','opened')
    for update of s skip locked
  ),
  ins as (
    insert into feedback (user_id, track_id, contact_id, submission_id, response_type, body)
    select user_id, track_id, contact_id, id, 'no_response',
           'Auto-logged: no response within the 14-day window.'
    from overdue
    returning submission_id
  )
  update submissions s
     set no_response_logged = true, updated_at = now()
    from ins
   where s.id = ins.submission_id;
  get diagnostics logged = row_count;
  return logged;
end;
$$;

-- ---------------------------------------------------------------------------
-- Enqueue reminder rows (the scheduled digest reads/sends these). One row per
-- (submission, kind); re-running never duplicates. kind: follow_up_nudge at 7d,
-- overdue at 14d.
-- ---------------------------------------------------------------------------
create or replace function queue_followup_notifications()
returns integer
language plpgsql
security definer
set search_path = public
as $$
declare queued int := 0; n int;
begin
  -- 7-day silence nudges
  insert into notifications (user_id, kind, payload, scheduled_for)
  select s.user_id, 'follow_up_nudge',
         jsonb_build_object('submission_id', s.id, 'contact_id', s.contact_id, 'track_id', s.track_id),
         now()
  from submissions s
  where s.follow_up_due_at is not null and s.follow_up_due_at <= now()
    and (s.overdue_at is null or s.overdue_at > now())
    and s.status in ('sent','opened')
    and not exists (
      select 1 from notifications x
      where x.user_id = s.user_id and x.kind = 'follow_up_nudge'
        and x.payload->>'submission_id' = s.id::text
    );
  get diagnostics n = row_count; queued := queued + n;

  -- 14-day overdue flags
  insert into notifications (user_id, kind, payload, scheduled_for)
  select s.user_id, 'overdue',
         jsonb_build_object('submission_id', s.id, 'contact_id', s.contact_id, 'track_id', s.track_id),
         now()
  from submissions s
  where s.overdue_at is not null and s.overdue_at <= now()
    and s.status in ('sent','opened')
    and not exists (
      select 1 from notifications x
      where x.user_id = s.user_id and x.kind = 'overdue'
        and x.payload->>'submission_id' = s.id::text
    );
  get diagnostics n = row_count; queued := queued + n;
  return queued;
end;
$$;

-- ---------------------------------------------------------------------------
-- One entrypoint for the daily scheduler.
-- ---------------------------------------------------------------------------
create or replace function run_followups_tick()
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  perform log_overdue_no_responses();
  perform queue_followup_notifications();
end;
$$;

-- ---------------------------------------------------------------------------
-- Schedule it daily at 08:00 UTC — only if pg_cron is available (it is on
-- Supabase). Guarded so this file also loads on a vanilla Postgres.
-- ---------------------------------------------------------------------------
do $$
begin
  if exists (select 1 from pg_available_extensions where name = 'pg_cron') then
    create extension if not exists pg_cron;
    perform cron.unschedule('demotrack_followups_tick')
      where exists (select 1 from cron.job where jobname = 'demotrack_followups_tick');
    perform cron.schedule('demotrack_followups_tick', '0 8 * * *', 'select run_followups_tick();');
  else
    raise notice 'pg_cron not available — schedule run_followups_tick() externally (it is enabled on Supabase).';
  end if;
end;
$$;

-- ---------------------------------------------------------------------------
-- Email digest: the daily-digest Edge Function composes & sends the digest.
-- On Supabase, trigger it from the same daily tick via pg_net (uncomment and
-- fill your project ref + a service-role/anon JWT stored in Vault). Left
-- commented because it is project-specific.
--
-- select cron.schedule(
--   'demotrack_daily_digest', '5 8 * * *',
--   $$ select net.http_post(
--        url     := 'https://<PROJECT_REF>.functions.supabase.co/daily-digest',
--        headers := jsonb_build_object('Content-Type','application/json',
--                     'Authorization','Bearer ' || current_setting('app.service_role_key', true))
--      ); $$
-- );
-- ---------------------------------------------------------------------------


-- ============================================================================
-- >>> link_tracking.sql
-- ============================================================================
-- ============================================================================
-- DemoTrack — Phase 11 (OPTIONAL): Demo Link Tracking (Spec §9)
-- Wrap Form/DM demo links so you can see when a label OPENS your demo.
-- Scoped to Form/DM only — never email (open-tracking hurts deliverability).
-- Standalone & idempotent. Run AFTER schema.sql with the service role.
--
-- Flow: app creates a tracked_links row (hash -> target_url) and pastes
-- track.<domain>/<hash> into the portal/DM. When opened, the track-redirect
-- Edge Function calls record_link_open(hash) -> logs a link_events row, flips
-- the submission to 'opened' (first open), and returns the real target to 302.
-- ============================================================================

create table if not exists tracked_links (
  id            uuid primary key default gen_random_uuid(),
  user_id       uuid not null references auth.users(id) on delete cascade,
  submission_id uuid references submissions(id) on delete cascade,
  hash          text not null unique,
  target_url    text not null,
  created_at    timestamptz not null default now()
);
create index if not exists tracked_links_user_idx on tracked_links(user_id);
create index if not exists tracked_links_submission_idx on tracked_links(submission_id);

alter table tracked_links enable row level security;
drop policy if exists owner_all on tracked_links;
create policy owner_all on tracked_links
  for all using (auth.uid() = user_id) with check (auth.uid() = user_id);

-- The opener is anonymous (a label clicking a link), so the redirect path runs
-- with SECURITY DEFINER and bypasses RLS — but only ever touches the one row
-- matching the hash, and copies user_id/submission_id from that row.
create or replace function record_link_open(p_hash text, p_user_agent text default null)
returns text
language plpgsql
security definer
set search_path = public
as $$
declare
  link tracked_links;
begin
  select * into link from tracked_links where hash = p_hash;
  if not found then
    return null;
  end if;

  insert into link_events (user_id, submission_id, hash, user_agent)
  values (link.user_id, link.submission_id, link.hash, p_user_agent);

  -- First open advances the funnel: sent -> opened (never downgrades).
  if link.submission_id is not null then
    update submissions
       set status = 'opened', updated_at = now()
     where id = link.submission_id and status = 'sent';
  end if;

  return link.target_url;
end;
$$;

-- Only the track-redirect Edge Function calls this, and it runs with the
-- service role — client roles never need EXECUTE (security-advisor 0028/0029).
revoke execute on function record_link_open(text, text) from public, anon, authenticated;
grant execute on function record_link_open(text, text) to service_role;

-- Per-submission open counts, for the UI (security_invoker => caller's RLS).
create or replace view submission_open_counts
  with (security_invoker = true) as
select s.id as submission_id, s.user_id,
       count(e.id)::int as opens,
       max(e.opened_at) as last_opened_at
from submissions s
left join link_events e on e.submission_id = s.id
where s.user_id = auth.uid()
group by s.id, s.user_id;




-- ============================================================================
-- >>> freshness.sql
-- ============================================================================
-- ============================================================================
-- DemoTrack — Data Freshness System (turns last_verified from a static stamp
-- into a self-updating signal). Standalone & idempotent. Run AFTER schema.sql
-- with the service role.
--
-- Provides:
--   • labels.link_status / link_checked_at  — written by the check-links cron
--     Edge Function (service role) — the only path allowed to touch the shared
--     read-only labels master.
--   • label_reports                — per-user write-back (RLS owner-only):
--     "this route is broken / changed / closed" or "I re-verified it, still works".
--   • label_freshness (view)       — labels + the caller's own reports, so the
--     UI can compute an effective, per-user freshness for every label.
--   • label_recheck_queue (view)   — the actionable worklist: stale, broken,
--     or link-checker-flagged labels.
--
-- The freshness *buckets* (fresh / aging / stale) live in src/lib/freshness.js
-- so there is one source of truth for thresholds; this layer only exposes the
-- raw inputs (effective verified date, flagged-broken, automated link status).
-- ============================================================================

-- ---------------------------------------------------------------------------
-- Layer 4 inputs: automated link-check results on the shared master.
-- Only the check-links Edge Function (service role) ever writes these.
-- link_status: 'ok' | 'broken' | 'timeout' | null (never checked / not a URL)
-- ---------------------------------------------------------------------------
alter table labels add column if not exists link_status     text;
alter table labels add column if not exists link_checked_at timestamptz;

-- ---------------------------------------------------------------------------
-- Layer 2: user write-back. labels is read-only to users, so reports live in
-- their own owner-scoped table and are overlaid on the master at read time.
-- ---------------------------------------------------------------------------
do $$
begin
  create type label_report_kind as enum
    ('broken_link', 'route_changed', 'closed', 'verified_ok');
exception
  when duplicate_object then null;
end
$$;

create table if not exists label_reports (
  id         uuid primary key default gen_random_uuid(),
  user_id    uuid not null references auth.users(id) on delete cascade,
  label_id   uuid not null references labels(id) on delete cascade,
  kind       label_report_kind not null,
  note       text,
  created_at timestamptz not null default now()
);
create index if not exists label_reports_user_idx  on label_reports(user_id);
create index if not exists label_reports_label_idx on label_reports(label_id);
create index if not exists label_reports_lookup_idx on label_reports(user_id, label_id, created_at desc);

alter table label_reports enable row level security;
drop policy if exists owner_all on label_reports;
create policy owner_all on label_reports
  for all using (auth.uid() = user_id) with check (auth.uid() = user_id);

-- ---------------------------------------------------------------------------
-- label_freshness: every label, enriched with THIS user's freshness signal.
-- security_invoker => labels' public read + the caller's own label_reports.
--
--   my_verified_at  — latest "verified_ok" the user logged (a real send that
--                     confirmed the route still works). Refreshes the master
--                     for that user without editing it.
--   flagged_broken  — the user has a broken/changed/closed report that is more
--                     recent than their last verified_ok (so marking it verified
--                     again clears the flag).
--   effective_verified — the better of the seed date and the user's own check.
-- ---------------------------------------------------------------------------
create or replace view label_freshness
  with (security_invoker = true) as
select
  l.id,
  l.name,
  l.tier,
  l.access_path,
  l.submission_method,
  l.contact_link,
  l.genre_tags,
  l.submission_requirements,
  l.sources,
  l.why,
  l.last_verified,
  l.link_status,
  l.link_checked_at,
  v.my_verified_at,
  greatest(l.last_verified, v.my_verified_at::date) as effective_verified,
  coalesce(b.flagged_broken, false)                 as flagged_broken
from labels l
left join lateral (
  select max(r.created_at) as my_verified_at
  from label_reports r
  where r.label_id = l.id
    and r.user_id  = auth.uid()
    and r.kind     = 'verified_ok'
) v on true
left join lateral (
  select exists (
    select 1
    from label_reports r
    where r.label_id = l.id
      and r.user_id  = auth.uid()
      and r.kind in ('broken_link', 'route_changed', 'closed')
      and r.created_at > coalesce(
        (select max(v2.created_at)
           from label_reports v2
          where v2.label_id = l.id
            and v2.user_id  = auth.uid()
            and v2.kind     = 'verified_ok'),
        '-infinity'::timestamptz)
  ) as flagged_broken
) b on true;

-- ---------------------------------------------------------------------------
-- label_recheck_queue: the actionable subset — anything a careful producer
-- should re-check before relying on it. The UI surfaces a "Needs re-check (N)".
--   reason: 'flagged' (you reported it) > 'link_broken' (cron) > 'stale' (>1yr)
-- ---------------------------------------------------------------------------
create or replace view label_recheck_queue
  with (security_invoker = true) as
select
  f.*,
  case
    when f.flagged_broken                          then 'flagged'
    when f.link_status = 'broken'                  then 'link_broken'
    when f.effective_verified is null              then 'unverified'
    when f.effective_verified < (now() - interval '365 days')::date then 'stale'
    else null
  end as recheck_reason
from label_freshness f
where f.flagged_broken
   or f.link_status = 'broken'
   or f.effective_verified is null
   or f.effective_verified < (now() - interval '365 days')::date;

-- ============================================================================
-- >>> restore_auth.sql (final state lock-down)
-- ============================================================================
-- Ensures a fresh setup ends in the same state as production: RLS enabled on
-- every table and no broad anon grants (left over from the old no-login mode).
-- The per-user views above are already defined against auth.uid(), so only the
-- RLS re-assertion + anon revoke from restore_auth.sql are needed here.

alter table contacts        enable row level security;
alter table tracks          enable row level security;
alter table submissions     enable row level security;
alter table feedback        enable row level security;
alter table templates       enable row level security;
alter table ar_intel        enable row level security;
alter table work_sessions   enable row level security;
alter table goals           enable row level security;
alter table link_events     enable row level security;
alter table press_kit       enable row level security;
alter table notifications   enable row level security;
alter table tracked_links   enable row level security;
alter table label_reports   enable row level security;
alter table labels          enable row level security;
alter table promo_contacts  enable row level security;

revoke select, insert, update, delete on all tables in schema public from anon;
revoke usage, select on all sequences in schema public from anon;
